import{_ as o,o as t,c as a,au as r}from"./chunks/framework.Bpqx6pAq.js";const u=JSON.parse('{"title":"Base Field","description":"","frontmatter":{},"headers":[],"relativePath":"api/core/mixins/mixins.base-field.md","filePath":"api/core/mixins/mixins.base-field.md"}'),l={name:"api/core/mixins/mixins.base-field.md"};function d(i,e,s,c,n,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="base-field" tabindex="-1">Base Field <a class="header-anchor" href="#base-field" aria-label="Permalink to &quot;Base Field&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The <code>baseField</code> mixin is the foundation for all form field components in KDK. It manages the field&#39;s internal model, error state, and a rich set of display-related computed properties derived from the field&#39;s JSON schema metadata. It is designed to be used alongside <a href="https://quasar.dev/vue-components/field" target="_blank" rel="noreferrer">Quasar field components</a>.</p><p>The model is initialised from the <code>values</code> prop on creation and kept in sync via a watcher.</p><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { baseField } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@kalisio/kdk/core/client&#39;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> default</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  mixins: [baseField],</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // ...</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Prop</th><th>Type</th><th>Required</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>values</code></td><td><code>Object</code></td><td>no</td><td><code>null</code></td><td>An object holding the current field values, keyed by field name. The mixin reads <code>values[properties.name]</code> to initialise and update the model.</td></tr><tr><td><code>properties</code></td><td><code>Object</code></td><td>yes</td><td>—</td><td>The JSON schema property descriptor for this field. Expected to contain a <code>field</code> sub-object with display configuration and a <code>name</code> key.</td></tr><tr><td><code>required</code></td><td><code>Boolean</code></td><td>no</td><td><code>false</code></td><td>Whether this field is required.</td></tr><tr><td><code>readOnly</code></td><td><code>Boolean</code></td><td>no</td><td><code>false</code></td><td>Whether this field is read-only.</td></tr><tr><td><code>dense</code></td><td><code>Boolean</code></td><td>no</td><td><code>false</code></td><td>Whether to use a compact (dense) display mode.</td></tr></tbody></table><h2 id="data" tabindex="-1">Data <a class="header-anchor" href="#data" aria-label="Permalink to &quot;Data&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>model</code></td><td><code>any</code></td><td><code>emptyModel()</code></td><td>The reactive value bound to the field input.</td></tr><tr><td><code>error</code></td><td><code>String</code></td><td><code>&#39;&#39;</code></td><td>The current validation error message. Empty when the field is valid.</td></tr></tbody></table><h2 id="computed-properties" tabindex="-1">Computed Properties <a class="header-anchor" href="#computed-properties" aria-label="Permalink to &quot;Computed Properties&quot;">​</a></h2><h3 id="label" tabindex="-1"><code>label</code> <a class="header-anchor" href="#label" aria-label="Permalink to &quot;`label`&quot;">​</a></h3><p>Returns the field&#39;s display label. Sources in priority order:</p><ol><li><code>properties.field.label</code> (translated if a valid i18n key)</li><li><code>properties.description</code> (JSON schema <code>description</code> metadata)</li></ol><ul><li><strong>Returns:</strong> <code>string</code></li></ul><h3 id="hashelper" tabindex="-1"><code>hasHelper</code> <a class="header-anchor" href="#hashelper" aria-label="Permalink to &quot;`hasHelper`&quot;">​</a></h3><p>Returns whether a helper is configured for this field.</p><ul><li><strong>Returns:</strong> <code>boolean</code></li></ul><h3 id="helperlabel" tabindex="-1"><code>helperLabel</code> <a class="header-anchor" href="#helperlabel" aria-label="Permalink to &quot;`helperLabel`&quot;">​</a></h3><p>Returns the helper&#39;s label text, from <code>properties.field.helper.label</code>.</p><ul><li><strong>Returns:</strong> <code>string | null</code></li></ul><h3 id="helpericon" tabindex="-1"><code>helperIcon</code> <a class="header-anchor" href="#helpericon" aria-label="Permalink to &quot;`helperIcon`&quot;">​</a></h3><p>Returns the helper&#39;s icon, from <code>properties.field.helper.icon</code>.</p><ul><li><strong>Returns:</strong> <code>string | undefined</code></li></ul><h3 id="helpertooltip" tabindex="-1"><code>helperTooltip</code> <a class="header-anchor" href="#helpertooltip" aria-label="Permalink to &quot;`helperTooltip`&quot;">​</a></h3><p>Returns the helper&#39;s tooltip text, from <code>properties.field.helper.tooltip</code>.</p><ul><li><strong>Returns:</strong> <code>string</code></li></ul><h3 id="helperurl" tabindex="-1"><code>helperUrl</code> <a class="header-anchor" href="#helperurl" aria-label="Permalink to &quot;`helperUrl`&quot;">​</a></h3><p>Returns the helper&#39;s URL, from <code>properties.field.helper.url</code>.</p><ul><li><strong>Returns:</strong> <code>string | null</code></li></ul><h3 id="helperdialog" tabindex="-1"><code>helperDialog</code> <a class="header-anchor" href="#helperdialog" aria-label="Permalink to &quot;`helperDialog`&quot;">​</a></h3><p>Returns the helper&#39;s dialog configuration, from <code>properties.field.helper.dialog</code>.</p><ul><li><strong>Returns:</strong> <code>Object | null</code></li></ul><h3 id="helpercontext" tabindex="-1"><code>helperContext</code> <a class="header-anchor" href="#helpercontext" aria-label="Permalink to &quot;`helperContext`&quot;">​</a></h3><p>Returns the helper&#39;s context object, from <code>properties.field.helper.context</code>.</p><ul><li><strong>Returns:</strong> <code>Object | null</code></li></ul><h3 id="hasfocus" tabindex="-1"><code>hasFocus</code> <a class="header-anchor" href="#hasfocus" aria-label="Permalink to &quot;`hasFocus`&quot;">​</a></h3><p>Returns whether the field should receive focus automatically, from <code>properties.field.focus</code>.</p><ul><li><strong>Returns:</strong> <code>boolean</code></li></ul><h3 id="haserror" tabindex="-1"><code>hasError</code> <a class="header-anchor" href="#haserror" aria-label="Permalink to &quot;`hasError`&quot;">​</a></h3><p>Returns whether the field currently has a validation error.</p><ul><li><strong>Returns:</strong> <code>boolean</code></li></ul><h3 id="errorlabel" tabindex="-1"><code>errorLabel</code> <a class="header-anchor" href="#errorlabel" aria-label="Permalink to &quot;`errorLabel`&quot;">​</a></h3><p>Returns the localized error message. Sources in priority order:</p><ol><li><code>properties.field.errorLabel</code> (explicit override, translated if a valid i18n key)</li><li><code>this.error</code> (set by <code>invalidate()</code>)</li></ol><ul><li><strong>Returns:</strong> <code>string</code></li></ul><h3 id="disabled" tabindex="-1"><code>disabled</code> <a class="header-anchor" href="#disabled" aria-label="Permalink to &quot;`disabled`&quot;">​</a></h3><p>Returns whether the field is disabled, from <code>properties.field.disabled</code>.</p><ul><li><strong>Returns:</strong> <code>boolean</code></li></ul><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to &quot;Methods&quot;">​</a></h2><h3 id="emptymodel" tabindex="-1"><code>emptyModel()</code> <a class="header-anchor" href="#emptymodel" aria-label="Permalink to &quot;`emptyModel()`&quot;">​</a></h3><p>Returns the &quot;empty&quot; value for this field type. Override in concrete field components to return a type-appropriate default (e.g. <code>&#39;&#39;</code>, <code>[]</code>, <code>{}</code>).</p><ul><li><strong>Returns:</strong> <code>null</code> by default.</li></ul><h3 id="isempty" tabindex="-1"><code>isEmpty()</code> <a class="header-anchor" href="#isempty" aria-label="Permalink to &quot;`isEmpty()`&quot;">​</a></h3><p>Checks whether the current model is equal to the empty model.</p><ul><li><strong>Returns:</strong> <code>boolean</code></li></ul><h3 id="value" tabindex="-1"><code>value()</code> <a class="header-anchor" href="#value" aria-label="Permalink to &quot;`value()`&quot;">​</a></h3><p>Returns the current model value. Override to add transformation logic before the value is read by the form.</p><ul><li><strong>Returns:</strong> the current <code>model</code>.</li></ul><h3 id="fill-value" tabindex="-1"><code>fill(value)</code> <a class="header-anchor" href="#fill-value" aria-label="Permalink to &quot;`fill(value)`&quot;">​</a></h3><p>Sets the model to <code>value</code> and clears any existing error.</p><ul><li><strong>Parameters:</strong><ul><li><code>value</code> <em>(any)</em>: The value to set.</li></ul></li></ul><h3 id="clear" tabindex="-1"><code>clear()</code> <a class="header-anchor" href="#clear" aria-label="Permalink to &quot;`clear()`&quot;">​</a></h3><p>Resets the model to the field&#39;s default value (<code>properties.default</code>) or to <code>emptyModel()</code> if no default is defined.</p><h3 id="validate" tabindex="-1"><code>validate()</code> <a class="header-anchor" href="#validate" aria-label="Permalink to &quot;`validate()`&quot;">​</a></h3><p>Clears the current error, marking the field as valid.</p><h3 id="invalidate-error" tabindex="-1"><code>invalidate(error)</code> <a class="header-anchor" href="#invalidate-error" aria-label="Permalink to &quot;`invalidate(error)`&quot;">​</a></h3><p>Sets the error message, marking the field as invalid.</p><ul><li><strong>Parameters:</strong><ul><li><code>error</code> <em>(string)</em>: The error message to display.</li></ul></li></ul><h3 id="async-onchanged" tabindex="-1"><code>async onChanged()</code> <a class="header-anchor" href="#async-onchanged" aria-label="Permalink to &quot;`async onChanged()`&quot;">​</a></h3><p>Should be called (or bound to an input event such as <code>blur</code>) whenever the model changes. It normalises <code>null</code> models for non-nullable fields, then emits a <code>field-changed</code> event so the parent form can re-validate.</p><ul><li><strong>Emits:</strong> <code>field-changed(propertyName, model)</code></li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Bind <code>onChanged</code> to Quasar&#39;s <a href="https://quasar.dev/vue-components/input#QInput-API" target="_blank" rel="noreferrer"><code>@update:modelValue</code></a> or <code>@blur</code> to trigger form validation on user interaction.</p></div><h3 id="apply-object-field" tabindex="-1"><code>apply(object, field)</code> <a class="header-anchor" href="#apply-object-field" aria-label="Permalink to &quot;`apply(object, field)`&quot;">​</a></h3><p>Applies the current field value onto <code>object[field]</code>. Override in concrete field components to perform custom transformations before the form is submitted.</p><ul><li><strong>Parameters:</strong><ul><li><code>object</code> <em>(Object)</em>: The target object being built for submission.</li><li><code>field</code> <em>(string)</em>: The key on <code>object</code> to set.</li></ul></li></ul><h3 id="submitted-object-field" tabindex="-1"><code>submitted(object, field)</code> <a class="header-anchor" href="#submitted-object-field" aria-label="Permalink to &quot;`submitted(object, field)`&quot;">​</a></h3><p>Called after the form has been successfully submitted. Does nothing by default — override to perform post-submission side effects.</p><ul><li><strong>Parameters:</strong><ul><li><code>object</code> <em>(Object)</em>: The service response object.</li><li><code>field</code> <em>(string)</em>: The field name.</li></ul></li></ul><h3 id="onhelperdialogconfirmed-context" tabindex="-1"><code>onHelperDialogConfirmed(context)</code> <a class="header-anchor" href="#onhelperdialogconfirmed-context" aria-label="Permalink to &quot;`onHelperDialogConfirmed(context)`&quot;">​</a></h3><p>Handler called when a helper dialog is confirmed. If <code>context.url</code> is set, opens it in a new browser tab using Quasar&#39;s <code>openURL</code>.</p><ul><li><strong>Parameters:</strong><ul><li><code>context</code> <em>(Object)</em>: The dialog confirmation context.</li></ul></li></ul><h2 id="lifecycle" tabindex="-1">Lifecycle <a class="header-anchor" href="#lifecycle" aria-label="Permalink to &quot;Lifecycle&quot;">​</a></h2><ul><li><strong><code>created</code></strong>: if <code>values</code> is set, calls <code>updateValue(values[properties.name])</code> to initialise the model.</li></ul><h2 id="watch" tabindex="-1">Watch <a class="header-anchor" href="#watch" aria-label="Permalink to &quot;Watch&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Behaviour</th></tr></thead><tbody><tr><td><code>values</code></td><td>When <code>values</code> changes, calls <code>updateValue(values[properties.name])</code> to sync the model, or <code>clear()</code> if <code>values</code> becomes <code>null</code>.</td></tr></tbody></table>',86)])])}const m=o(l,[["render",d]]);export{u as __pageData,m as default};
